/*
 * checksum -- compute a Fletcher64 checksum
 */
uint64_t

checksum(void *addr, size_t len)
{
    uint32_t *p32 = addr;
    uint32_t *p32end = addr + len;
    uint32_t lo32 = 0;
    uint32_t hi32 = 0;

    while (p32 < p32end) {
    lo32 += *p32++;
    hi32 += lo32;
    }

    return (uint64_t)hi32 << 32 | lo32;
}
